import ConnectButton from "@components/common/connect-button";
import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const tonServices = () => {
  return (
    <section className="hero-wrapper item-center gap-2xl">
      <h2 className="about-h2 font-black c-text-center md-c-text-start">
        TON Wallet Development Services – Your Gateway to Effortless Digital
        Asset Management?
      </h2>
      <div className="flex-center md-flex-column gap-2xl">
        <div className="item-start gap-xl w-100">
          <p className="about-p">
            Curious about the TON blockchain? Well, you will need a TON wallet
            to access it! In layman’s terms, a TON wallet is your gateway to the
            TON blockchain. TON wallets store your valuable assets and act as
            intermediaries, seamlessly connecting you to the TON ecosystem.
            <br />
            <br />
            These digital wallets have been specifically designed to manage,
            store, and transact Toncoin, the native cryptocurrency of TON. Did
            you know that TON wallets provide multiple options depending on the
            requirements? Yep, you heard that right. There is TON wallet,
            Tonkeeper, and Tonhub, to name a few. Being designed with user
            autonomy and security in mind, TON wallets have garnered the
            attention of seasoned crypto traders and long-term investors. These
            wallets are your all-inclusive solution to manage your Ton coins
            within the TON ecosystem. Be among the first to build your TON
            Wallet by partnering with Justtry, a custom TON wallet development
            company.
          </p>
          <ConnectButton justifyContentPosition={"justify-content-center"} />
        </div>
        <StaticImage
          src="../../../styles/assets/images/ton-wallet/ton_wallet_service.png"
          alt="ton wallet service image"
          fetchpriority="high"
          layout="constrained"
          width={800}
          quality={75}
          loading="eager"
          placeholder="none"
        />
      </div>
    </section>
  );
};

export default tonServices;
