import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import TonWalletScreen from "@screens/ton-wallet";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const TonWalletPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Ton wallet Development Company", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.tonWalletDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "TON wallet development company specializing in fast, secure, and customizable wallet solutions built for the TON blockchain and Telegram ecosystem.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1602",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is TON wallet ?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A TON wallet is a digital wallet used to store, send, and manage Toncoin (TON) and other assets on the TON blockchain.",
            },
          },
          {
            "@type": "Question",
            name: "How to make a TON wallet?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Create a TON wallet by choosing a trusted wallet app, generating a new wallet, securely saving the recovery phrase, and setting up security to start using Toncoin on the TON blockchain.",
            },
          },
          {
            "@type": "Question",
            name: "What are the essential tools for TON wallet creation?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Essential TON wallet tools include TON SDK, TON Web libraries, secure key management, smart contracts, and APIs for seamless blockchain interaction.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <TonWalletScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default TonWalletPage;

export const queryData = graphql`
  query MyQuery {
    tonWalletDevImg: file(relativePath: { eq: "ton-wallet-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "ton-wallet-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
