import ConnectButton from "@components/common/connect-button";
import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const tonWorks = () => {
  return (
    <section className="light-gray-bg">
      <div className="hero-wrapper flex-center md-flex-column gap-2xl">
        <div className="w-100">
          <StaticImage
            src="../../../styles/assets/images/ton-wallet/ton_works.png"
            alt="Ton wallet App"
            className="w-100"
            fetchpriority="high"
            layout="constrained"
            quality={75}
            loading="eager"
            placeholder="none"
          />
        </div>
        <div className="w-100 item-start c-gap">
          <h2 className="about-h2 font-black c-text-start">
            How Does Our TON Wallet Work?
          </h2>
          <p>
            A TON wallet is similar to a bank account, but with some advanced
            features that make it more secure and private. The first difference
            is a seed phrase. This is a list of 12 words that act like a master
            password. If you forget your login info, you can use this seed
            phrase to get back into your digital wallet. But remember to keep it
            confidential. Another difference is your wallet address. This is a
            unique code (like your bank account number) that you give to people
            when you want them to send you Toncoin.
            <br />
            <br />
            With a TON wallet, you don&apos;t need to give out your personal
            information. Transactions use just your wallet address, keeping
            things anonymous.TON wallets are also extremely fast, so you
            won&apos;t be waiting for ages when you buy something with Toncoin.
            Also, TON wallets are capable of more than just sending and
            receiving money. <br />
            <br />
            You can use Toncoin to pay for services inside the TON network, like
            games or apps. Furthermore, Toncoin empowers you to participate in
            TON&apos;s governance. By holding Toncoin, you gain the right to
            vote on proposals that influence the platform&apos;s development and
            future goals. Finally, TON uses a system called Proof-of-Stake to
            keep things running smoothly. This makes transaction fees on the TON
            network much cheaper than on other networks, so you can send and
            receive Toncoin without breaking the bank!
          </p>
          <ConnectButton />
        </div>
      </div>
    </section>
  );
};

export default tonWorks;
