import React from "react";
import tailored from "@styles/assets/images/utilsicons/tailored.svg";
import user_interface from "@styles/assets/images/utilsicons/user_interface.svg";
import security from "@styles/assets/images/utilsicons/security.svg";
import feature from "@styles/assets/images/utilsicons/feature.svg";
import perfomance from "@styles/assets/images/utilsicons/perfomance.svg";

const gridItems = [
  {
    title: "Ironclad Security",
    icon: security,
  },
  {
    title: "Custom-Tailored",
    icon: tailored,
  },
  {
    title: "Enticing User Interface",
    icon: user_interface,
  },
  {
    title: "Feature-Packed",
    icon: feature,
  },
];

const singleItem = "Blazing-Fast Performance";
const singleItemIcon = perfomance;
const whyJusttry = () => {
  return (
    <section className="hero-wrapper item-center gap-2xl">
      <div className="item-start gap-2xl">
        <h2 className="about-h2 font-black c-text-center md-c-text-start">
          Why choose Justtry Technologies for TON Wallet Development
        </h2>
        <p className="about-p c-text-center md-c-text-start">
          To succeed in the evolving cryptoverse, you need a secure and
          feature-rich TON wallet built for performance and trust. This is where
          Justtry Technologies stands apart. <br />
          <br />
          We are a leading cryptocurrency wallet development company with proven
          expertise in building robust, multi-functional wallets across diverse
          blockchain ecosystems. Our blockchain specialists design TON wallets
          that prioritize security, usability, and seamless integration. From
          custom architecture to advanced security layers, we deliver
          appropriate solutions to your business goals. develop with Justtry
          Technologies to build a TON wallet that empowers users and drives
          long-term growth.
        </p>
      </div>
      <div className="why-dao-section-head item-center gap-md p-2">
        <div className="c-grid grid-two why-dao-section gap-md ">
          {gridItems.map((item, index) => (
            <div
              key={index}
              className="style-items flex-center gap-sm position-relative"
            >
              <img src={item.icon} alt={item.title} width={24} />
              <p className="about-p-two"> {item.title}</p>
            </div>
          ))}
        </div>

        <div className="w-100 style-item-single flex-center gap-sm position-relative">
          <img src={singleItemIcon} alt={singleItem} width={24} />
          <p className="about-p-two c-text-center md-c-text-start">
            {singleItem}
          </p>
        </div>
      </div>
    </section>
  );
};

export default whyJusttry;
